(21, 24, 1, 'Một hành trình giữa mơ và thực, nơi trí tưởng tượng dẫn dắt người đọc qua những miền ký ức kỳ lạ.', 'from api.models import User\nfrom django.contrib.auth.hashers import make_password, check_password\n\nu = User.objects.get(username=\"ketnoithanhcong\")\nu.password = make_password(\"123456\")\nu.role = \"Admin\"\nu.save()\n\nprint(check_password(\"123456\", u.password))', 3, '2026-04-27 16:28:06'),
(24, 24, 2, 'Đồng cảm', 'Tôi thấy mình trong quyển sách này', 3, '2026-05-07 02:38:11'),
(25, 24, 4, 'Theo đuổi “vận mệnh” của bản thân', 'Truyện kể về Santiago — một chàng chăn cừu người Tây Ban Nha — lên đường đi tìm kho báu sau khi có m', 4, '2026-05-07 03:05:50'),
(26, 24, 3, 'Tại sao tác phẩm này lại nổi tiếng?', 'tầm quan trọng của việc viết “mã sạch” (clean code).\nTác giả cho rằng code không chỉ để máy chạy được mà còn phải dễ đọc, dễ hiểu và dễ bảo trì cho con người.\n\nRobert C. Martin nhấn mạnh:\n\nlập trình viên dành nhiều thời gian đọc và sửa code hơn là viết code mới,\ncode xấu sẽ làm dự án khó phát triển,\ncode sạch giúp teamwork và bảo trì dễ hơn.\n\nChương này cũng giải thích:\n\nthế nào là clean code,\ntác hại của code bừa bộn,\ntrách nhiệm nghề nghiệp của lập trình viên.\n\nThông điệp chính:\n\n“Hãy luôn để đoạn code sạch hơn lúc bạn tìm thấy nó.”', 4, '2026-05-07 04:25:45'),
(27, 24, 4, 'Tại sao tác phẩm này lại nổi tiếng?', '{book.so_luong_ton ?? book.stock ?? book.quantity ?? 0}', 4, '2026-05-07 09:26:29');

